import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.DXCpk3D_.js";const u=JSON.parse('{"title":"Template Variables","description":"","frontmatter":{},"headers":[],"relativePath":"reference/template-variables.md","filePath":"reference/template-variables.md"}'),n={name:"reference/template-variables.md"};function r(l,e,o,p,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="template-variables" tabindex="-1">Template Variables <a class="header-anchor" href="#template-variables" aria-label="Permalink to &quot;Template Variables&quot;">​</a></h1><p>Prompt templates in workflow steps use <strong>Jinja2 templating</strong> (powered by Nunjucks). These are the available variable namespaces.</p><h2 id="variable-reference" tabindex="-1">Variable Reference <a class="header-anchor" href="#variable-reference" aria-label="Permalink to &quot;Variable Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><span><code>{{ precedent_output }}</code></span></td><td><code>string</code></td><td>Output from the previous step (empty for step 1 unless provided via webhook/manual run)</td></tr><tr><td><span><code>{{ properties.KEY }}</code></span></td><td><code>string</code></td><td>Property value from the 3-tier merged variable map</td></tr><tr><td><span><code>{{ credentials.KEY }}</code></span></td><td><code>string</code></td><td>Credential value from the 3-tier merged variable map</td></tr><tr><td><span><code>{{ env.KEY }}</code></span></td><td><code>string</code></td><td>Environment-injected variable value</td></tr><tr><td><span><code>{{ inputs.KEY }}</code></span></td><td><code>string</code></td><td>Webhook parameter / manual run input value</td></tr></tbody></table><h2 id="precedent-output" tabindex="-1"><code>precedent_output</code> <a class="header-anchor" href="#precedent-output" aria-label="Permalink to &quot;\`precedent_output\`&quot;">​</a></h2><p>The output from the previous step in the workflow pipeline.</p><ul><li><strong>Step 1</strong>: Empty string by default. If the workflow was triggered by webhook or manual run, the raw payload or first input value may appear here.</li><li><strong>Step N</strong> (N &gt; 1): The <code>output</code> field from step N-1&#39;s execution record.</li></ul><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Based on the previous analysis:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{ precedent_output }}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Provide a summary.</span></span></code></pre></div><h2 id="properties" tabindex="-1"><code>properties.*</code> <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;\`properties.*\`&quot;">​</a></h2><p>Property variables resolved via the <a href="/open-agent-orchestra/1.30.11/concepts/variables.html">3-tier override system</a>:</p><ol><li><strong>Workspace</strong> variables (lowest priority)</li><li><strong>User</strong> variables (medium priority)</li><li><strong>Agent</strong> variables (highest priority)</li></ol><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the market for {{ properties.MARKET_SYMBOL }}.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Current risk limit: {{ properties.MAX_RISK_PERCENT }}%</span></span></code></pre></div><h2 id="credentials" tabindex="-1"><code>credentials.*</code> <a class="header-anchor" href="#credentials" aria-label="Permalink to &quot;\`credentials.*\`&quot;">​</a></h2><p>Credential variables resolved via the same 3-tier system. All credentials are stored encrypted (AES-256-GCM) and decrypted only at render time in memory.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Connect to the API using key: {{ credentials.API_KEY }}</span></span></code></pre></div><h2 id="env" tabindex="-1"><code>env.*</code> <a class="header-anchor" href="#env" aria-label="Permalink to &quot;\`env.*\`&quot;">​</a></h2><p>Variables marked with <code>injectAsEnvVariable: true</code>. These are also written to a <code>.env</code> file in the agent workspace directory at runtime.</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Database host: {{ env.DB_HOST }}</span></span></code></pre></div><h2 id="inputs" tabindex="-1"><code>inputs.*</code> <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;\`inputs.*\`&quot;">​</a></h2><p>Parameters passed via webhook trigger or manual run. These are defined in the webhook trigger&#39;s <strong>parameter definitions</strong> and validated at trigger time.</p><h3 id="defining-parameters" tabindex="-1">Defining Parameters <a class="header-anchor" href="#defining-parameters" aria-label="Permalink to &quot;Defining Parameters&quot;">​</a></h3><p>When creating a webhook trigger, define parameters with:</p><ul><li><strong>Name</strong> — the key used in templates</li><li><strong>Required</strong> — whether the parameter must be provided</li><li><strong>Description</strong> — optional help text shown in the Manual Run dialog</li></ul><h3 id="using-inputs" tabindex="-1">Using Inputs <a class="header-anchor" href="#using-inputs" aria-label="Permalink to &quot;Using Inputs&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the stock symbol {{ inputs.symbol }} over the {{ inputs.timeframe }} timeframe.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% if inputs.include_news %}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Include recent news in the analysis.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endif %}</span></span></code></pre></div><h3 id="how-inputs-are-populated" tabindex="-1">How Inputs Are Populated <a class="header-anchor" href="#how-inputs-are-populated" aria-label="Permalink to &quot;How Inputs Are Populated&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trigger Source</th><th>How <code>inputs</code> is populated</th></tr></thead><tbody><tr><td><strong>Webhook</strong> (<code>POST /api/webhooks/:path</code>)</td><td>Extracted from the request body, validated against parameter definitions</td></tr><tr><td><strong>Manual Run</strong> (UI button)</td><td>User fills in input fields based on parameter definitions</td></tr><tr><td><strong>Cron / Datetime / Event</strong></td><td>Empty object (<code>{}</code>)</td></tr></tbody></table><h2 id="jinja2-features" tabindex="-1">Jinja2 Features <a class="header-anchor" href="#jinja2-features" aria-label="Permalink to &quot;Jinja2 Features&quot;">​</a></h2><p>Full Jinja2 syntax is supported — conditionals, loops, filters, and expressions:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% if inputs.symbol %}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze {{ inputs.symbol | upper }}.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% else %}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Analyze the default watchlist.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endif %}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% for symbol in properties.WATCHLIST.split(&#39;,&#39;) %}</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Check {{ symbol | trim }}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{% endfor %}</span></span></code></pre></div>`,30)])])}const k=a(n,[["render",r]]);export{u as __pageData,k as default};
